// 取得 AI Agent 的回應
const input = $input.all()[0].json;
let aiResponse;
try {
  // 嘗試從不同位置取得資料
  aiResponse = input.output || input.text || input;

  // 如果是字串，清理 markdown 標記並解析
  if (typeof aiResponse === 'string') {
    aiResponse = aiResponse
      .replace(/```json\s*/g, '')  // 移除 ```json
      .replace(/```\s*/g, '')      // 移除 ```
      .trim();

    aiResponse = JSON.parse(aiResponse);
  }

  // 記錄解析後的資料（除錯用）
  console.log('解析後的 AI 回應:', JSON.stringify(aiResponse).substring(0, 200));

} catch (error) {
  // 記錄原始資料以便除錯
  console.log('原始輸入:', JSON.stringify(input).substring(0, 500));
  throw new Error('無法解析 AI 回應: ' + error.message);
}
// 驗證必要欄位
if (!aiResponse.complexion || !aiResponse.dietary) {
  console.log('資料結構錯誤:', JSON.stringify(aiResponse).substring(0, 500));
  throw new Error('AI 回應缺少 complexion 或 dietary 欄位');
}
if (!aiResponse.complexion.score || !aiResponse.complexion.overall_review || !aiResponse.complexion.top_issues) {
  throw new Error('complexion 資料不完整');
}
if (!aiResponse.dietary.suggestions) {
  throw new Error('dietary 資料不完整');
}
// 組合按摩建議
const topIssues = aiResponse.complexion.top_issues || [];
const massages = topIssues.map(issue => issueMapping[issue]).filter(Boolean);
// 回傳結果
return {
  json: {
    sectionA: {
      photoUrl: $('request(YOLO)').item.json.old_image_url,
      score: aiResponse.complexion.score,
      evaluation: aiResponse.complexion.overall_review,
      massages: massages,
      topIssues: topIssues
    },
    suggestions: aiResponse.dietary.suggestions,
    analyzed_at: new Date().toISOString()
  }
};
